256	/**
257	 * An ISO-8601 calendar date (`YYYY-MM-DD`). The conference data is day-granular,
258	 * so the document stores plain dates; the `Content` boundary (C3) widens each to
259	 * the existing end-of-day-UTC millisecond used by the route code (`use-the-platform`).
260	 *
261	 * Two checks, both required (`make-impossible-states-unrepresentable`):
262	 *   1. the `YYYY-MM-DD` textual shape, and
263	 *   2. that the components name a *real* calendar day — the pattern alone admits
264	 *      impossible dates like `2026-99-99`, `2026-02-31`, or a Feb-29 in a
265	 *      non-leap year, which must never cross the boundary as a typed `IsoDate`.
266	 * Validity is proven by constructing the UTC date and confirming it round-trips
267	 * to the same year/month/day (a rolled-over date — e.g. Feb 31 → Mar 3 — differs).
268	 */
269	const isoCalendarDateFilter = Schema.makeFilter<string>(
270	  (value) => {
271	    // The `^\d{4}-\d{2}-\d{2}$` pattern check runs first, so the slices below
272	    // are always present and numeric here.
273	    const year = Number.parseInt(value.slice(0, 4), 10);
274	    const month = Number.parseInt(value.slice(5, 7), 10);
275	    const day = Number.parseInt(value.slice(8, 10), 10);
276	    const date = new Date(Date.UTC(year, month - 1, day));
277	    if (
278	      date.getUTCFullYear() !== year ||
279	      date.getUTCMonth() !== month - 1 ||
280	      date.getUTCDate() !== day
281	    ) {
282	      return `IsoDate must be a real calendar date, got "${value}"`;
283	    }
284	    return undefined;
285	  },
286	  { title: 'IsoDate' },
287	);
