289	export const IsoDate = Schema.NonEmptyString.check(
290	  Schema.isPattern(/^\d{4}-\d{2}-\d{2}$/, { title: 'IsoDate' }),
291	  isoCalendarDateFilter,
292	).pipe(Schema.brand('IsoDate'));
